'use strict';
({params, imports}) => {
    const programEncounter = params.entity;
    const formElement = params.formElement;
    const statusBuilder = new imports.rulesConfig.FormElementStatusBuilder({programEncounter, formElement});
    const encounterDateTime = programEncounter.encounterDateTime;

    let answersToBeShown = [];

    const recommendedActivities = programEncounter.programEnrolment.getEncountersOfType('Recommended Activities', true)
        .filter((enc) => enc.encounterDateTime && enc.encounterDateTime < encounterDateTime);

    if(recommendedActivities && recommendedActivities.length > 0) {
        const latest = recommendedActivities[0];
        const questionGroup = latest.getObservationValue('1387b5a2-c738-4c24-b96b-efe724620e7a') || [];

        for (let j = 0; j < questionGroup.length; j++) {
            let typeOfActivity = questionGroup[j].findObservationByConceptUUID('37dbc501-19ae-406d-b1de-0bab5c3743d4');
            let recommendedBy = questionGroup[j].findObservationByConceptUUID('b8571b8b-7185-4b3b-bd6a-20c6ab6efaa5');
            if (typeOfActivity && recommendedBy && recommendedBy.getReadableValue() === 'CDA') {
                typeOfActivity = typeOfActivity.getValue();
                answersToBeShown.push(typeOfActivity);
            }
        }
    }

    if (answersToBeShown && answersToBeShown.length > 0) {
        const activities = '37dbc501-19ae-406d-b1de-0bab5c3743d4';
        let cdaRecommendations = answersToBeShown.map(value => ({ [activities]: value }));
        statusBuilder.value(cdaRecommendations);
    }

    statusBuilder.show().whenItem(answersToBeShown && answersToBeShown.length > 0).is.truthy;

    return statusBuilder.build();
};

