'use strict';
({params, imports}) => {
  const programEnrolment = params.entity;
  const formElement = params.formElement;
  const moment = imports.moment;
  const statusBuilder = new imports.rulesConfig.FormElementStatusBuilder({programEnrolment, formElement});

  const lmp = moment(programEnrolment.getObservationValue('Last Menstrual Period date'));
  const nowMinus495Days = moment().subtract(495, 'days');

  if (lmp.isBefore(nowMinus495Days)) {
      statusBuilder.validationError("Last Menstrual Period date must be within 495 days from today");   
  }
  if (lmp.isAfter(moment())) {
      statusBuilder.validationError("Last Menstrual Period date must be in the past");   
  }

  return statusBuilder.build();
};

