  "visitScheduleRule": "//SAMPLE RULE EXAMPLE\n\"use strict\";\n({ params, imports }) => {\n  const programEncounter = params.entity;\n  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({\n    programEncounter\n  });\n  \n  const moment = imports.moment;\n  const _ = imports.lodash;\n  const cancelReason = programEncounter.findCancelEncounterObservationReadableValue(\"Cancel reason\");\n  \n  const earliestDate = moment(programEncounter.earliestVisitDateTime).add(1, 'month').startOf('month').toDate();\n  let isEditScenario = programEncounter.programEnrolment.encounters.some((enc) => \n            enc.encounterType.name === 'Growth Monitoring' && \n            enc.voided === false && \n            imports.moment(enc.earliestVisitDateTime).isSame(earliestDate, 'day')\n          );\n    \n\n    // greater than 5yrs children with any cancellation reason\n\n    if (cancelReason && programEncounter.programEnrolment.individual.getAgeInYears() >= 5)\n  return scheduleBuilder.getAll();\n\n    if(programEncounter.programEnrolment.individual.getAgeInYears() < 5 && cancelReason != 'Death' && cancelReason != 'Migrated to other geography' && !isEditScenario) {\n        scheduleBuilder.add({\n            name: 'Growth Monitoring',\n            encounterType: 'Growth Monitoring',\n            earliestDate: earliestDate,\n            maxDate:  moment(earliestDate).endOf('month').toDate()\n        });\n    }\n  \n  return scheduleBuilder.getAll();\n};",
