  "visitScheduleRule": "\"use strict\";\n({ params, imports }) => {\n  const encounter = params.entity;\n  const moment = imports.moment;\n  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({encounter});\n  \n  const editFlag = encounter.individual.getEncounters(true).filter(enc => enc.encounterType.name == 'Detailed Registration' && enc.voided == false).length\n  \n  if(!editFlag){\n    const condition11 = new imports.rulesConfig.RuleCondition({encounter}).when.valueInEncounter(\"14cb8d22-49c8-4b9c-ad8a-bbb4bd18e3c9\").containsAnswerConceptNameOtherThan(\"d00ef10a-ec39-4597-a137-42b813102146\").and.when.valueInEncounter(\"14cb8d22-49c8-4b9c-ad8a-bbb4bd18e3c9\").containsAnswerConceptNameOtherThan(\"d9435939-69cb-4e25-a723-ed082da87200\").matches();\n    \n    const condition21 = new imports.rulesConfig.RuleCondition({encounter}).when.valueInEncounter(\"18d212b1-0b7e-4e82-822f-39d557c3d018\").containsAnswerConceptNameOtherThan(\"d00ef10a-ec39-4597-a137-42b813102146\").and.when.valueInEncounter(\"18d212b1-0b7e-4e82-822f-39d557c3d018\").containsAnswerConceptNameOtherThan(\"d9435939-69cb-4e25-a723-ed082da87200\").and.when.valueInEncounter(\"18d212b1-0b7e-4e82-822f-39d557c3d018\").containsAnswerConceptNameOtherThan(\"e4f8a0f8-1ed2-46e1-aef6-f0f0ab6fb702\").matches();\n    \n    const condition31 = new imports.rulesConfig.RuleCondition({encounter}).when.valueInEncounter(\"4b775b84-70c4-4347-8163-253698f268c0\").containsAnswerConceptNameOtherThan(\"d00ef10a-ec39-4597-a137-42b813102146\").and.when.valueInEncounter(\"4b775b84-70c4-4347-8163-253698f268c0\").containsAnswerConceptNameOtherThan(\"d9435939-69cb-4e25-a723-ed082da87200\").matches();\n    \n    if(condition11 || condition21 || condition31 ){\n      const earliestDate = moment(encounter.encounterDateTime).add(0, 'days').toDate();\n      const maxDate = moment(encounter.encounterDateTime).add(4, 'days').toDate();\n      scheduleBuilder.add({name: \"Detailed Registration\", encounterType: \"Detailed Registration\", earliestDate, maxDate});  \n      scheduleBuilder.add({name: \"Lab Report Delivered to Patient\", encounterType: \"Lab Report Delivered to Patient\", earliestDate, maxDate});\n    }\n  }\n   \n  const confirmed = encounter.individual.getEncounters(true).filter(enc => enc.encounterType.name == 'Confirmation' && enc.voided == false);\n  \n  const sampleRequiredAgainCount = encounter.individual.getEncounters(true).filter(enc => enc.encounterType.name == 'Sample Required Again' && enc.voided == false).length;\n  \n  if(confirmed.length === sampleRequiredAgainCount + 1){\n    //if(encounter.encounterDateTime === null){\n      const condition41 = new imports.rulesConfig.RuleCondition({encounter}).when.valueInEncounter(\"14cb8d22-49c8-4b9c-ad8a-bbb4bd18e3c9\").containsAnswerConceptName(\"d9435939-69cb-4e25-a723-ed082da87200\").or.when.valueInEncounter(\"18d212b1-0b7e-4e82-822f-39d557c3d018\").containsAnswerConceptName(\"d9435939-69cb-4e25-a723-ed082da87200\").or.when.valueInEncounter(\"4b775b84-70c4-4347-8163-253698f268c0\").containsAnswerConceptName(\"d9435939-69cb-4e25-a723-ed082da87200\").matches();\n      if(condition41){\n        const earliestDate = moment(encounter.encounterDateTime).add(0, 'days').toDate();\n        const maxDate = moment(encounter.encounterDateTime).add(4, 'days').toDate();\n        scheduleBuilder.add({name: \"Sample Required Again\", encounterType: \"Sample Required Again\", earliestDate, maxDate}); \n      }\n    //}\n  }\n  \n  return scheduleBuilder.getAll();\n};",
